// Minimalist JS for Vulnerable Shop
const API_URL = 'http://localhost:8080';

// Global State
let currentUser = null;
let cart = [];

// DOM Elements
const itemsContainer = document.getElementById('items-container');
const loginBtn = document.getElementById('login-btn');
const regBtn = document.getElementById('reg-btn');
const authSection = document.getElementById('auth-section');
const userInfo = document.getElementById('user-info');
const usernameDisplay = document.getElementById('username-display');

// Init
async function init() {
    await loadItems();
}

async function loadItems() {
    // For now, hardcoded 3 items as per requirement, or we could fetch from BE
    // itemsContainer.innerHTML = 'Loading items...';
    // const res = await fetch(`${API_URL}/items`);
    // const items = await res.json();
    const items = [
        { id: 1, name: 'Vulnerable Shield', price: 99.99 },
        { id: 2, name: 'Insecure Sword', price: 150.00 },
        { id: 3, name: 'Leaky Potion', price: 25.50 }
    ];

    itemsContainer.innerHTML = '';
    items.forEach(item => {
        const div = document.createElement('div');
        div.className = 'item';
        div.innerHTML = `
            <h3>${item.name}</h3>
            <p>Price: $${item.price}</p>
            <button onclick="addToCart(${item.id}, '${item.name}')">Buy</button>
        `;
        itemsContainer.appendChild(div);
    });
}

window.addToCart = (id, name) => {
    if (!currentUser) {
        alert('You must be logged in to buy items!');
        return;
    }
    cart.push({ id, name });
    renderCart();
};

function renderCart() {
    const cartSection = document.getElementById('cart-section');
    const cartItems = document.getElementById('cart-items');
    cartSection.classList.remove('hidden');
    cartItems.innerHTML = cart.map(i => `<p>${i.name}</p>`).join('');
}

// TODO: Implement login, register, history fetch with cookie auth

init();

