package com.example.vulnerableapp;

import jakarta.servlet.http.Cookie;
import jakarta.servlet.http.HttpServletResponse;
import org.springframework.beans.factory.annotation.Autowired;
import org.springframework.web.bind.annotation.*;

import java.util.Map;
import java.util.Optional;

@RestController
@RequestMapping("/api")
@CrossOrigin(origins = "http://localhost", allowCredentials = "true")
public class UserController {

    @Autowired
    private UserRepository userRepository;

    @PostMapping("/register")
    public String register(@RequestBody User user) {
        userRepository.save(user);
        return "User registered successfully";
    }

    @PostMapping("/login")
    public String login(@RequestBody Map<String, String> credentials, HttpServletResponse response) {
        String username = credentials.get("username");
        String password = credentials.get("password");

        Optional<User> user = userRepository.findByUsername(username);
        if (user.isPresent() && user.get().getPassword().equals(password)) {
            Cookie cookie = new Cookie("user_id", user.get().getId().toString());
            cookie.setPath("/");
            cookie.setMaxAge(3600); // 1 hour
            response.addCookie(cookie);
            return "Login successful";
        } else {
            throw new RuntimeException("Invalid credentials");
        }
    }

    @GetMapping("/me")
    public User me(@CookieValue(name = "user_id", required = false) String userId) {
        if (userId == null) throw new RuntimeException("Not logged in");
        return userRepository.findById(Long.parseLong(userId)).orElseThrow();
    }
}

