    @Autowired
    private OrderRepository orderRepository;

    @PostMapping("/create")
    public Order createOrder(@CookieValue(name = "user_id", required = false) String userId) {
        if (userId == null) throw new RuntimeException("Not logged in");
        Order order = new Order(Long.parseLong(userId));
        return orderRepository.save(order);
    }

