            throw new RuntimeException("Unauthorized");
        }
        order.setStatus("COMPLETED");
        return orderRepository.save(order);
    }

    @GetMapping("/history")
    public List<Order> getHistory(@CookieValue(name = "user_id", required = false) String userId) {
        if (userId == null) throw new RuntimeException("Not logged in");
        return orderRepository.findByUserId(Long.parseLong(userId));
    }
}

