package com.example.vulnerableapp;

import org.springframework.beans.factory.annotation.Autowired;
import org.springframework.web.bind.annotation.*;
import java.util.List;

@RestController
@RequestMapping("/api/admin")
@CrossOrigin(origins = "http://localhost", allowCredentials = "true")
public class AdminController {

    @Autowired
    private UserRepository userRepository;

    @Autowired
    private OrderRepository orderRepository;

    private void checkAdmin(String userId) {
        if (userId == null) throw new RuntimeException("Not logged in");
        User user = userRepository.findById(Long.parseLong(userId)).orElseThrow();
        if (!"ADMIN".equals(user.getRole())) {
            throw new RuntimeException("Admin access required");
        }
    }

    @GetMapping("/users")
    public List<User> getAllUsers(@CookieValue(name = "user_id", required = false) String userId) {
        checkAdmin(userId);
        return userRepository.findAll();
    }

    @GetMapping("/orders")
    public List<Order> getAllOrders(@CookieValue(name = "user_id", required = false) String userId) {
        checkAdmin(userId);
        return orderRepository.findAll();
    }
}

