// DOM Elements
const itemsContainer = document.getElementById('items-container');
const loginForm = document.getElementById('login-form');
const registerForm = document.getElementById('register-form');
const authSection = document.getElementById('auth-section');
const userInfo = document.getElementById('user-info');
const usernameDisplay = document.getElementById('username-display');
const historySection = document.getElementById('history-section');
const historyList = document.getElementById('history-list');

// Event Listeners
document.getElementById('show-login').onclick = () => { loginForm.classList.remove('hidden'); registerForm.classList.add('hidden'); };
document.getElementById('show-register').onclick = () => { registerForm.classList.remove('hidden'); loginForm.classList.add('hidden'); };
document.getElementById('login-btn').onclick = login;
document.getElementById('reg-btn').onclick = register;
document.getElementById('logout-btn').onclick = logout;
document.getElementById('view-history').onclick = loadHistory;
document.getElementById('confirm-purchase').onclick = confirmPurchase;

// Init
async function init() {
    await checkSession();
    await loadItems();
}

async function checkSession() {
    try {
        const res = await fetch(`${API_URL}/api/me`, { credentials: 'include' });
        if (res.ok) {
            currentUser = await res.json();
            showLoggedIn();
        }
    } catch (e) { console.log('Not logged in'); }
}

function showLoggedIn() {
    authSection.classList.add('hidden');
    loginForm.classList.add('hidden');
    registerForm.classList.add('hidden');
    userInfo.classList.remove('hidden');
    usernameDisplay.innerText = currentUser.username;
}

async function login() {
    const username = document.getElementById('login-username').value;
    const password = document.getElementById('login-password').value;
    const res = await fetch(`${API_URL}/api/login`, {
        method: 'POST',
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify({ username, password }),
        credentials: 'include'
    });
    if (res.ok) {
        alert('Logged in!');
        location.reload();
    } else alert('Login failed');
}

async function register() {
    const username = document.getElementById('reg-username').value;
    const password = document.getElementById('reg-password').value;
    const res = await fetch(`${API_URL}/api/register`, {
        method: 'POST',
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify({ username, password })
    });
    if (res.ok) {
        alert('Registered! Now please login.');
        registerForm.classList.add('hidden');
    } else alert('Registration failed');
}

function logout() {
    document.cookie = "user_id=; expires=Thu, 01 Jan 1970 00:00:00 UTC; path=/;";
    location.reload();
}

async function loadItems() {
    try {
        const res = await fetch(`${API_URL}/api/items`);
        const items = await res.json();
        itemsContainer.innerHTML = '';
        items.forEach(item => {
            const div = document.createElement('div');
            div.className = 'item';
            div.innerHTML = `
                <h3>${item.name}</h3>
                <p>Price: $${item.price}</p>
                <button onclick="addToCart(${item.id}, '${item.name}')">Buy</button>
            `;
            itemsContainer.appendChild(div);
        });
    } catch (e) { itemsContainer.innerHTML = 'Error loading items.'; }
}

window.addToCart = async (id, name) => {
    if (!currentUser) {
        alert('You must be logged in to buy items!');
        return;
    }
    // Phase 1: Creation
    const res = await fetch(`${API_URL}/api/orders/create`, { method: 'POST', credentials: 'include' });
    if (res.ok) {
        const order = await res.json();
        cart.push(order);
        renderCart();
    } else alert('Failed to create order');
};

function renderCart() {
    const cartSection = document.getElementById('cart-section');
    const cartItems = document.getElementById('cart-items');
    cartSection.classList.remove('hidden');
    cartItems.innerHTML = cart.map(o => `<p>Order #${o.id} - Status: ${o.status}</p>`).join('');
}

async function confirmPurchase() {
    // Phase 2: Confirmation
    for (let order of cart) {
        if (order.status === 'PENDING') {
            await fetch(`${API_URL}/api/orders/${order.id}/confirm`, { method: 'POST', credentials: 'include' });
        }
    }
    alert('Purchase confirmed!');
    cart = [];
    document.getElementById('cart-section').classList.add('hidden');
    loadHistory();
}

async function loadHistory() {
    const res = await fetch(`${API_URL}/api/orders/history`, { credentials: 'include' });
    if (res.ok) {
        const orders = await res.json();
        historySection.classList.remove('hidden');
        historyList.innerHTML = orders.map(o => `<p>Order #${o.id} - Status: ${o.status} - Date: ${o.createdAt}</p>`).join('');
    }
}

init();

